PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wikibase: <http://wikiba.se/ontology#>

SELECT ?game ?amount ?unitLabel ?duration_minutes
WHERE {
  VALUES ?series {
    wd:Q3511178    # 1975 ALCS
    wd:Q14870260   # 2013 ALCS
    wd:Q56692089   # 2018 World Series
  }
  ?series wdt:P527 ?game .
  ?game wdt:P710 wd:Q213959 ;
        wdt:P2042 ?duration_q .
  ?duration_q wikibase:quantityAmount ?amount ;
              wikibase:quantityUnit ?unit .
  SERVICE wikibase:label { 
    ?unit rdfs:label ?unitLabel .
    FILTER(LANG(?unitLabel) = "en")
  }
  FILTER(?unit IN (wd:Q2529, wd:Q712226, wd:Q11573))
  BIND(IF(?unit = wd:Q2529, ?amount * 60,
        IF(?unit = wd:Q712226, ?amount,
        IF(?unit = wd:Q11573, ?amount / 60, 0)
        )) AS ?duration_minutes)
}
ORDER BY DESC(?duration_minutes)
LIMIT 10

