PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>

SELECT (MAX(?duration_minutes) AS ?max_duration)
WHERE {
  VALUES ?series {
    wd:Q3511178    # 1975 ALCS
    wd:Q14870260   # 2013 ALCS
    wd:Q56692089   # 2018 World Series
  }
  ?game wdt:P361 ?series ;
        wdt:P710 wd:Q213959 ;
        wdt:P580 ?start ;
        wdt:P582 ?end .
  BIND(xsd:integer((?end - ?start)/xsd:duration('PT1M')) AS ?duration_minutes)
}
ORDER BY DESC(?duration_minutes)
LIMIT 1

